#!/usr/bin/env node

import { createClient } from '@supabase/supabase-js';

// Configuration
const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL;
const SUPABASE_SERVICE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!SUPABASE_URL || !SUPABASE_SERVICE_KEY) {
  console.error('❌ Missing Supabase credentials');
  process.exit(1);
}

const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_KEY);

console.log('🧪 M7 Operations Smoke Test');
console.log('============================\n');

async function testKillSwitch() {
  console.log('1️⃣ Testing Kill Switch...');

  try {
    // Test with ANALYSIS_DISABLED=true
    const { data, error } = await supabase.rpc('enqueue_analysis', {
      p_contract_id: 'test-contract-id',
      p_org_id: 'test-org-id'
    });

    if (error) {
      if (error.message.includes('temporarily disabled')) {
        console.log('✅ Kill switch working - analysis blocked');
      } else {
        console.log('❌ Unexpected error:', error.message);
      }
    } else {
      console.log('❌ Kill switch not working - analysis allowed');
    }
  } catch (error) {
    console.log('❌ Kill switch test failed:', error.message);
  }
}

async function testRateLimit() {
  console.log('\n2️⃣ Testing Rate Limit...');

  try {
    const testOrgId = 'test-org-rate-limit';

    // First request should succeed
    const { data: first, error: firstError } = await supabase.rpc('check_and_increment_daily_usage', {
      p_org_id: testOrgId,
      p_daily_limit: 1
    });

    if (firstError) {
      console.log('❌ First rate limit check failed:', firstError.message);
      return;
    }

    console.log('✅ First request allowed:', first[0]?.message);

    // Second request should be blocked
    const { data: second, error: secondError } = await supabase.rpc('check_and_increment_daily_usage', {
      p_org_id: testOrgId,
      p_daily_limit: 1
    });

    if (secondError) {
      console.log('❌ Second rate limit check failed:', secondError.message);
    } else if (second && second[0]?.allowed === false) {
      console.log('✅ Rate limit working - second request blocked');
    } else {
      console.log('❌ Rate limit not working - second request allowed');
    }
  } catch (error) {
    console.log('❌ Rate limit test failed:', error.message);
  }
}

async function testBackpressure() {
  console.log('\n3️⃣ Testing Backpressure...');

  try {
    // Insert test queued analyses to simulate queue depth
    const testOrgId = 'test-org-backpressure';

    for (let i = 0; i < 5; i++) {
      await supabase
        .from('analyses')
        .insert({
          id: `test-analysis-${i}-${Date.now()}`,
          org_id: testOrgId,
          contract_id: `test-contract-${i}`,
          status: 'queued',
          created_at: new Date(Date.now() - i * 60000).toISOString() // Stagger by 1 minute
        });
    }

    // Check queue health
    const { data: analyses, error } = await supabase
      .from('analyses')
      .select('id, created_at')
      .eq('status', 'queued')
      .eq('org_id', testOrgId)
      .order('created_at');

    if (error) {
      console.log('❌ Backpressure test failed:', error.message);
    } else {
      const depth = analyses?.length || 0;
      const oldestAge = analyses?.length > 0 
        ? Math.floor((Date.now() - new Date(analyses[0].created_at).getTime()) / 60000)
        : 0;

      console.log(`✅ Queue depth: ${depth}, oldest age: ${oldestAge}min`);

      // Cleanup test data
      await supabase
        .from('analyses')
        .delete()
        .eq('org_id', testOrgId);
    }
  } catch (error) {
    console.log('❌ Backpressure test failed:', error.message);
  }
}

async function testCostGuardrails() {
  console.log('\n4️⃣ Testing Cost Guardrails...');

  try {
    const testAnalysisId = 'test-analysis-cost-' + Date.now();

    // Test within limits
    const { data: withinLimits, error: limitsError } = await supabase.rpc('validate_analysis_limits', {
      p_analysis_id: testAnalysisId,
      p_chunk_count: 10,
      p_char_count: 1000,
      p_tokens_in: 500,
      p_tokens_out: 300
    });

    if (limitsError) {
      console.log('❌ Cost guardrails test failed:', limitsError.message);
    } else if (withinLimits && withinLimits[0]?.allowed) {
      console.log('✅ Cost guardrails working - within limits');
    } else {
      console.log('❌ Cost guardrails not working:', withinLimits);
    }

    // Test exceeding limits
    const { data: exceededLimits, error: exceededError } = await supabase.rpc('validate_analysis_limits', {
      p_analysis_id: testAnalysisId + '-exceeded',
      p_chunk_count: 100, // Exceeds default limit of 50
      p_char_count: 1000,
      p_tokens_in: 500,
      p_tokens_out: 300
    });

    if (exceededError) {
      console.log('❌ Cost guardrails exceeded test failed:', exceededError.message);
    } else if (exceededLimits && exceededLimits[0]?.truncated) {
      console.log('✅ Cost guardrails working - limits exceeded, truncated');
    } else {
      console.log('❌ Cost guardrails not truncating when exceeded');
    }
  } catch (error) {
    console.log('❌ Cost guardrails test failed:', error.message);
  }
}

async function cleanup() {
  console.log('\n🧹 Cleaning up test data...');

  try {
    // Clean up test usage records
    await supabase
      .from('org_usage_daily')
      .delete()
      .like('org_id', 'test-org-%');

    // Clean up test analyses
    await supabase
      .from('analyses')
      .delete()
      .like('org_id', 'test-org-%');

    console.log('✅ Cleanup completed');
  } catch (error) {
    console.log('❌ Cleanup failed:', error.message);
  }
}

async function runTests() {
  try {
    await testKillSwitch();
    await testRateLimit();
    await testBackpressure();
    await testCostGuardrails();
    await cleanup();

    console.log('\n🎉 All smoke tests completed!');
  } catch (error) {
    console.error('\n❌ Smoke test suite failed:', error);
    process.exit(1);
  }
}

runTests();

import { AnalysisPanel } from "@/modules/analysis/components/AnalysisPanel";
import { getLatestAnalysisForContract } from "@/modules/analysis/lib/queries";
import { adaptAnalysisForClient } from "@/modules/analysis/lib/type-adapter";
import { getCurrentOrgIdOrThrow } from "@/modules/auth/lib/current-org";
import { ContractDetailActions } from "@/modules/contracts/components/contract-detail-actions";
import { getContractById } from "@/modules/contracts/lib/contracts";
import { format } from "date-fns";
import AppLayout from "../../layout";

interface ContractDetailPageProps {
  params: {
    contractId: string;
    locale: string;
  };
}

export default async function ContractDetailPage({
  params,
}: ContractDetailPageProps) {
  const { contractId } = params;

  try {
    // Get current org and verify contract access
    const orgId = await getCurrentOrgIdOrThrow();
    const contract = await getContractById(contractId);

    if (!contract) {
      return (
        <div className="container mx-auto py-8">
          <div className="text-center">
            <h1 className="text-2xl font-bold text-gray-900 mb-4">
              Contract Not Found
            </h1>
            <p className="text-gray-600 mb-8">
              The contract you're looking for doesn't exist or you don't have
              access to it.
            </p>
            <a
              href="/contracts"
              className="inline-flex items-center px-4 py-2 bg-primary text-white rounded-md hover:bg-primary/90"
            >
              Back to Contracts
            </a>
          </div>
        </div>
      );
    }

    // Get latest analysis for this contract
    const serverAnalysis = await getLatestAnalysisForContract(
      contractId,
      orgId,
    );
    const analysis = adaptAnalysisForClient(serverAnalysis);

    // Extract file name from file_url
    const fileName = contract.file_url
      ? contract.file_url.split("/").pop() || "Unknown"
      : "No file";

    return (
      <AppLayout>
        <div className="p-6 space-y-6">
          {/* Header */}
          <div>
            <h1 className="text-3xl font-bold text-foreground">
              {contract.title}
            </h1>
            <p className="text-muted-foreground">
              Contract analysis and risk assessment
            </p>
            {/* Status Timeline */}
            <div className="bg-white rounded-lg border p-6 mt-6">
              <h2 className="text-xl font-semibold mb-4">Status Timeline</h2>
              <div className="space-y-4">
                <div className="flex items-center space-x-3">
                  <div
                    className={`w-3 h-3 rounded-full ${
                      [
                        "draft",
                        "active",
                        "expired",
                        "terminated",
                        "pending_review",
                      ].includes(contract.status)
                        ? "bg-green-500"
                        : "bg-gray-300"
                    }`}
                  />
                  <div>
                    <p className="text-sm font-medium">Uploaded</p>
                    <p className="text-xs text-gray-500">
                      {format(contract.created_at || new Date(), "PPp")}
                    </p>
                  </div>
                </div>

                {contract.status === "active" && (
                  <div className="flex items-center space-x-3">
                    <div className="w-3 h-3 rounded-full bg-green-500" />
                    <div>
                      <p className="text-sm font-medium">Active</p>
                      <p className="text-xs text-gray-500">
                        Contract is active and ready
                      </p>
                    </div>
                  </div>
                )}

                {(contract.status === "expired" ||
                  contract.status === "terminated") && (
                  <div className="flex items-center space-x-3">
                    <div className="w-3 h-3 rounded-full bg-red-500" />
                    <div>
                      <p className="text-sm font-medium">
                        {contract.status === "expired"
                          ? "Expired"
                          : "Terminated"}
                      </p>
                      <p className="text-xs text-gray-500">
                        Contract is no longer active
                      </p>
                    </div>
                  </div>
                )}

                {contract.status === "pending_review" && (
                  <div className="flex items-center space-x-3">
                    <div className="w-3 h-3 rounded-full bg-blue-500" />
                    <div>
                      <p className="text-sm font-medium">Pending Review</p>
                      <p className="text-xs text-gray-500">
                        Contract is under review
                      </p>
                    </div>
                  </div>
                )}

                {(contract.status === "queued" ||
                  contract.status === "processing") && (
                  <div className="flex items-center space-x-3">
                    <div
                      className={`w-3 h-3 rounded-full ${
                        contract.status === "queued"
                          ? "bg-yellow-500"
                          : "bg-blue-500 animate-pulse"
                      }`}
                    />
                    <div>
                      <p className="text-sm font-medium">
                        {contract.status === "queued" ? "Queued" : "Processing"}
                      </p>
                      <p className="text-xs text-gray-500">
                        {contract.status === "queued"
                          ? "Analysis is queued"
                          : "Analysis in progress"}
                      </p>
                    </div>
                  </div>
                )}

                {contract.status === "completed" && (
                  <div className="flex items-center space-x-3">
                    <div className="w-3 h-3 rounded-full bg-green-500" />
                    <div>
                      <p className="text-sm font-medium">Analysis Complete</p>
                      <p className="text-xs text-gray-500">
                        Contract analysis completed
                      </p>
                    </div>
                  </div>
                )}

                {contract.status === "failed" && (
                  <div className="flex items-center space-x-3">
                    <div className="w-3 h-3 rounded-full bg-red-500" />
                    <div>
                      <p className="text-sm font-medium">Analysis Failed</p>
                      <p className="text-xs text-gray-500">
                        Analysis encountered an error
                      </p>
                    </div>
                  </div>
                )}

                <div className="flex items-center space-x-3 opacity-50">
                  <div className="w-3 h-3 rounded-full bg-gray-300" />
                  <div>
                    <p className="text-sm font-medium">Analyzed (Future)</p>
                    <p className="text-xs text-gray-500">Analysis complete</p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Actions Sidebar */}
          <div className="lg:col-span-1 space-y-6">
            <AnalysisPanel contract={contract} analysis={analysis} />
            <ContractDetailActions contract={contract} />
          </div>
        </div>
      </AppLayout>
    );
  } catch (error) {
    // Handle authentication errors gracefully
    return (
      <div className="container mx-auto py-8">
        <div className="text-center">
          <h1 className="text-2xl font-semibold text-gray-900">
            Access Denied
          </h1>
          <p className="mt-2 text-gray-600">
            You need to be logged in to view contracts.
          </p>
        </div>
      </div>
    );
  }
}

"use client";

import { createClient } from "@supabase/supabase-js";
import { useRouter } from "next/navigation";
import { useRef, useState } from "react";
import { useFormStatus } from "react-dom";
import {
    createContractDraftAction,
    finalizeContractUploadAction,
    initialContractDraftState,
    initialFinalizeUploadState,
} from "./actions";

const MAX_FILE_SIZE = 20 * 1024 * 1024; // 20MB
const ALLOWED_MIME_TYPES = [
  "application/pdf",
  "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
];

function SubmitButton({
  children,
  disabled,
}: {
  children: React.ReactNode;
  disabled?: boolean;
}) {
  const { pending } = useFormStatus();

  return (
    <button
      type="submit"
      disabled={pending || disabled}
      className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-primary hover:bg-primary/90 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-ring disabled:opacity-50 disabled:cursor-not-allowed"
    >
      {children}
    </button>
  );
}

export function ContractUpload() {
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const router = useRouter();

  const handleFileSelect = async (
    event: React.ChangeEvent<HTMLInputElement>,
  ) => {
    const file = event.target.files?.[0];
    if (!file) return;

    // Clear previous messages
    setError(null);
    setSuccess(null);

    // Validate file
    if (!ALLOWED_MIME_TYPES.includes(file.type)) {
      setError("Only PDF and DOCX files are allowed");
      return;
    }

    if (file.size > MAX_FILE_SIZE) {
      setError("File size must be less than 20MB");
      return;
    }

    setIsUploading(true);
    setUploadProgress(0);

    try {
      // Step 1: Create contract draft
      const formData = new FormData();
      formData.append("title", file.name);

      const draftResponse = await createContractDraftAction(
        initialContractDraftState,
        formData,
      );

      if (draftResponse.status === "error") {
        throw new Error(draftResponse.message);
      }

      if (!draftResponse.data) {
        throw new Error("No upload data received");
      }

      // Step 2: Upload file to Supabase Storage
      const supabase = createClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
      );

      const { error: uploadError } = await supabase.storage
        .from("contracts")
        .upload(draftResponse.data.uploadPath, file, {
          upsert: false,
        });

      if (uploadError) {
        throw new Error(`Upload failed: ${uploadError.message}`);
      }

      // Step 3: Finalize contract record
      const finalizeFormData = new FormData();
      finalizeFormData.append("contractId", draftResponse.data.contractId);
      finalizeFormData.append("filePath", draftResponse.data.uploadPath);

      const finalizeResponse = await finalizeContractUploadAction(
        initialFinalizeUploadState,
        finalizeFormData,
      );

      if (finalizeResponse.status === "error") {
        throw new Error(finalizeResponse.message);
      }

      // Success!
      setSuccess("Contract uploaded successfully");
      router.refresh();
      if (fileInputRef.current) {
        fileInputRef.current.value = "";
      }
      setUploadProgress(0);
    } catch (error) {
      console.error("Upload failed:", error);
      setError(error instanceof Error ? error.message : "Upload failed");
    } finally {
      setIsUploading(false);
      setUploadProgress(0);
    }
  };

  return (
    <div className="border rounded-lg p-6">
      <form>
        <div className="mb-4">
          <label
            htmlFor="file"
            className="block text-sm font-medium text-gray-700 mb-2"
          >
            Select Contract File
          </label>
          <input
            ref={fileInputRef}
            type="file"
            id="file"
            accept=".pdf,.docx,application/pdf,application/vnd.openxmlformats-officedocument.wordprocessingml.document"
            onChange={handleFileSelect}
            disabled={isUploading}
            className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-md file:border-0 file:text-sm file:font-semibold file:bg-primary file:text-white hover:file:bg-primary/90 disabled:opacity-50"
          />
          <p className="mt-1 text-sm text-gray-500">
            PDF and DOCX files up to 20MB
          </p>
        </div>

        {isUploading && (
          <div className="mb-4">
            <div className="flex items-center justify-between mb-2">
              <span className="text-sm font-medium">Uploading...</span>
              <span className="text-sm text-gray-500">{uploadProgress}%</span>
            </div>
            <div className="w-full bg-gray-200 rounded-full h-2">
              <div
                className="bg-primary h-2 rounded-full transition-all duration-300"
                style={{ width: `${uploadProgress}%` }}
              />
            </div>
          </div>
        )}

        {error && (
          <div className="mb-4 p-3 bg-red-50 border border-red-200 text-red-700 rounded-md">
            {error}
          </div>
        )}

        {success && (
          <div className="mb-4 p-3 bg-green-50 border border-green-200 text-green-700 rounded-md">
            {success}
          </div>
        )}
      </form>
    </div>
  );
}

